  1→import { useRef, useCallback, useEffect, useState } from 'react';
  2→import { useEditor } from '@/app/EditorProvider';
  3→import { useProject } from '@/app/ProjectProvider';
  4→import { usePlanClipboardController } from '@/clipboard/usePlanClipboardController';
  5→import { normalizeRectBounds } from '@/clipboard/planClipboard';
  6→import { getFloorElevation } from '@/domain/floorModels';
  7→import { useEditorTool } from '@/editor/useEditorTool';
  8→import { MIN_ZOOM, MAX_ZOOM, ZOOM_FACTOR } from '@/domain/defaults';
  9→import { TOOLS } from '@/editor/tools';
 10→import ClipboardPreviewLayer from './ClipboardPreviewLayer';
 11→import GridRenderer from './GridRenderer';
 12→import SlabRenderer from './SlabRenderer';
 13→import WallRenderer from './WallRenderer';
 14→import BeamRenderer from './BeamRenderer';
 15→import StairRenderer from './StairRenderer';
 16→import DoorRenderer from './DoorRenderer';
 17→import WindowRenderer from './WindowRenderer';
 18→import RoomRenderer from './RoomRenderer';
 19→import AnnotationRenderer from './AnnotationRenderer';
 20→import ElevationRenderer from './ElevationRenderer';
 21→import SectionRenderer from './SectionRenderer';
 22→import SelectionOverlay from './SelectionOverlay';
 23→import DimensionPreview from './DimensionPreview';
 24→import WallPreview from './WallPreview';
 25→import LandingRenderer from './LandingRenderer';
 26→import LandingPreview from './LandingPreview';
 27→import ColumnRenderer from './ColumnRenderer';
 28→import ColumnPreview from './ColumnPreview';
 29→import FixtureRenderer from './FixtureRenderer';
 30→import FixturePreview from './FixturePreview';
 31→import BeamPreview from './BeamPreview';
 32→import StairPreview from './StairPreview';
 33→import SlabPreview from './SlabPreview';
 34→import DoorWindowPreview from './DoorWindowPreview';
 35→import RoomPreview from './RoomPreview';
 36→import SectionCutRenderer from './SectionCutRenderer';
 37→import SectionCutPreview from './SectionCutPreview';
 38→import RegionSelectionOverlay from './RegionSelectionOverlay';
 39→import { ExpandIcon, CollapseIcon } from '@/ui/ToolbarIcons';
 40→import { isTypingTarget } from '@/utils/keyboard';
 41→import styles from './SvgCanvas.module.css';
 42→
 43→function screenToModel(screenX, screenY, viewport, svgRect) {
 44→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 45→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 46→  return { x, y };
 47→}
 48→
 49→export default function SvgCanvas() {
 50→  const svgRef = useRef(null);
 51→  const isPanning = useRef(false);
 52→  const lastPanPos = useRef({ x: 0, y: 0 });
 53→  const spaceHeld = useRef(false);
 54→  const cursorPosRef = useRef({ x: 0, y: 0 });
 55→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 56→
 57→  const { project, dispatch, getFloor } = useProject();
 58→  const editor = useEditor();
 59→  const {
 60→    activeTool, selectedId, selectedType, toolState,
 61→    viewport, showGrid, snapEnabled, activeFloorId, statusMessage, viewMode, activeSectionCutId,
 62→    regionSelection, pastePreview, maximizedPanel,
 63→    dispatch: editorDispatch,
 64→  } = editor;
 65→
 66→  const floor = getFloor(activeFloorId);
 67→  const {
 68→    copySelection,
 69→    cutSelection,
 70→    beginPaste,
 71→    updatePastePreview,
 72→    cancelPaste,
 73→    placePaste,
 74→    previewContent,
 75→  } = usePlanClipboardController();
 76→
 77→  const tool = useEditorTool({
 78→    activeTool,
 79→    dispatch,
 80→    editorDispatch,
 81→    project,
 82→    getFloor,
 83→    activeFloorId,
 84→    viewport,
 85→    snapEnabled,
 86→    selectedId,
 87→    selectedType,
 88→    toolState,
 89→    viewMode,
 90→  });
 91→
 92→  const getModelPos = useCallback((e) => {
 93→    const rect = svgRef.current.getBoundingClientRect();
 94→    return screenToModel(e.clientX, e.clientY, viewport, rect);
 95→  }, [viewport]);
 96→
 97→  const handleMouseDown = useCallback((e) => {
 98→    // Middle mouse or space+left for pan
 99→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
100→      isPanning.current = true;
101→      lastPanPos.current = { x: e.clientX, y: e.clientY };
102→      e.preventDefault();
103→      return;
104→    }
105→
106→    const modelPos = getModelPos(e);
107→    if (pastePreview?.active && e.button === 0) {
108→      placePaste(modelPos);
109→      return;
110→    }
111→    tool.onMouseDown(modelPos, e);
112→  }, [getModelPos, pastePreview, placePaste, tool]);
113→
114→  const handleMouseMove = useCallback((e) => {
115→    if (isPanning.current) {
116→      const dx = e.clientX - lastPanPos.current.x;
117→      const dy = e.clientY - lastPanPos.current.y;
118→      editorDispatch({ type: 'PAN', dx, dy });
119→      lastPanPos.current = { x: e.clientX, y: e.clientY };
120→      return;
121→    }
122→
123→    const modelPos = getModelPos(e);
124→    cursorPosRef.current = modelPos;
125→    setCursorPos(modelPos);
126→    if (pastePreview?.active) {
127→      updatePastePreview(modelPos);
128→      return;
129→    }
130→    tool.onMouseMove(modelPos, e);
131→  }, [getModelPos, pastePreview, tool, updatePastePreview, editorDispatch]);
132→
133→  const handleMouseUp = useCallback((e) => {
134→    if (isPanning.current) {
135→      isPanning.current = false;
136→      return;
137→    }
138→    if (pastePreview?.active) return;
139→    const modelPos = getModelPos(e);
140→    tool.onMouseUp(modelPos, e);
141→  }, [getModelPos, pastePreview, tool]);
142→
143→  const handleDoubleClick = useCallback((e) => {
144→    if (pastePreview?.active) return;
145→    const modelPos = getModelPos(e);
146→    tool.onDoubleClick(modelPos, e);
147→  }, [getModelPos, pastePreview, tool]);
148→
149→  const handleWheel = useCallback((e) => {
150→    e.preventDefault();
151→    const rect = svgRef.current.getBoundingClientRect();
152→    const mouseX = e.clientX - rect.left;
153→    const mouseY = e.clientY - rect.top;
154→
155→    const direction = e.deltaY < 0 ? 1 : -1;
156→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
157→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
158→
159→    // Zoom centered on cursor
160→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
161→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
162→
163→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
164→  }, [viewport, editorDispatch]);
165→
166→  useEffect(() => {
167→    if (!statusMessage) return undefined;
168→
169→    const timer = window.setTimeout(() => {
170→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
171→    }, 2500);
172→
173→    return () => window.clearTimeout(timer);
174→  }, [statusMessage, editorDispatch]);
175→
176→  useEffect(() => {
177→    const handleKeyDown = (e) => {
178→      if (isTypingTarget(e.target)) return;
179→
180→      if (e.key === ' ') {
181→        spaceHeld.current = true;
182→        e.preventDefault();
183→      }
184→
185→      if ((e.ctrlKey || e.metaKey) && viewMode === 'plan') {
186→        const key = e.key.toLowerCase();
187→        if (key === 'c') {
188→          e.preventDefault();
189→          copySelection();
190→          return;
191→        }
192→        if (key === 'x') {
193→          e.preventDefault();
194→          cutSelection();
195→          return;
196→        }
197→        if (key === 'v') {
198→          e.preventDefault();
199→          beginPaste(cursorPosRef.current);
200→          return;
201→        }
202→      }
203→
204→      if (e.key === 'Escape' && pastePreview?.active) {
205→        e.preventDefault();
206→        cancelPaste();
207→        return;
208→      }
209→
210→      // Tool shortcuts
211→      if (viewMode === 'plan' && !e.ctrlKey && !e.metaKey) {
212→        switch (e.key.toLowerCase()) {
213→          case 'v':
214→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
215→            return;
216→          case 'm':
217→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DIMENSION });
218→            return;
219→          case 'w':
220→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WALL });
221→            return;
222→          case 'b':
223→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.BEAM });
224→            return;
225→          case 't':
226→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.STAIR });
227→            return;
228→          case 'q':
229→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SECTION });
230→            return;
231→          case 's':
232→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SLAB });
233→            return;
234→          case 'r':
235→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOM });
236→            return;
237→          case 'd':
238→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
239→            return;
240→          case 'n':
241→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WINDOW });
242→            return;
243→          case 'c':
244→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.COLUMN });
245→            return;
246→          case 'l':
247→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.LANDING });
248→            return;
249→          case 'f':
250→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.FIXTURE });
251→            editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { fixtureType: 'kitchenTop', previewRotation: 0 } });
252→            return;
253→        }
254→      }
255→
256→      tool.onKeyDown(e);
257→    };
258→
259→    const handleKeyUp = (e) => {
260→      if (isTypingTarget(e.target)) return;
261→
262→      if (e.key === ' ') {
263→        spaceHeld.current = false;
264→      }
265→    };
266→
267→    window.addEventListener('keydown', handleKeyDown);
268→    window.addEventListener('keyup', handleKeyUp);
269→    return () => {
270→      window.removeEventListener('keydown', handleKeyDown);
271→      window.removeEventListener('keyup', handleKeyUp);
272→    };
273→  }, [beginPaste, cancelPaste, copySelection, cutSelection, pastePreview?.active, tool, editorDispatch, viewMode]);
274→
275→  // Prevent default context menu on SVG
276→  useEffect(() => {
277→    const svg = svgRef.current;
278→    if (!svg) return;
279→    const prevent = (e) => e.preventDefault();
280→    svg.addEventListener('contextmenu', prevent);
281→    svg.addEventListener('wheel', handleWheel, { passive: false });
282→    return () => {
283→      svg.removeEventListener('contextmenu', prevent);
284→      svg.removeEventListener('wheel', handleWheel);
285→    };
286→  }, [handleWheel]);
287→
288→  const cursor = spaceHeld.current ? 'grab' : pastePreview?.active ? 'copy' : tool.getCursor();
289→  const zoomPercent = Math.round(viewport.zoom * 1000);
290→  const displayedTool = viewMode.startsWith('elevation_') ? 'select' : activeTool;
291→  const isCanvasMaximized = maximizedPanel === 'canvas';
292→  const marqueeBounds = toolState.dragType === 'marquee' && toolState.startPos && toolState.currentPos
293→    ? normalizeRectBounds(toolState.startPos, toolState.currentPos)
294→    : null;
295→  const selectionCount = regionSelection?.objectCount || 0;
296→
297→  return (
298→    <div className={styles.canvasContainer}>
299→      <svg
300→        ref={svgRef}
301→        className={styles.svg}
302→        style={{ cursor }}
303→        onMouseDown={handleMouseDown}
304→        onMouseMove={handleMouseMove}
305→        onMouseUp={handleMouseUp}
306→        onDoubleClick={handleDoubleClick}
