            rx={width * 0.02} fill="none" {...PRIMARY} {...NSS} />
          {/* Left armrest */}
          <rect x={-hw + pad} y={-hd + backH} width={armW} height={depth - backH - pad}
            rx={width * 0.015} fill="none" {...PRIMARY} {...NSS} />
