          <rect x={hw - armW - pad} y={-hd + backH} width={armW} height={depth - backH - pad}
            rx={width * 0.015} fill="none" {...PRIMARY} {...NSS} />
          {/* 3 seat cushion rects */}
          {[0, 1, 2].map(i => (
            <rect key={i}
