          {[1, 2].map(i => (
            <line key={i}
              x1={seatLeft + i * cushionW} y1={seatTop + pad}
              x2={seatLeft + i * cushionW} y2={seatBot - pad}
              {...SECONDARY} {...NSS} fill="none"
              strokeDasharray="8 6"
