  9→export function createPreviewViewport(container) {
 10→  const materialPalette = createMaterialPalette();
 11→  const scene = new THREE.Scene();
 12→  scene.background = null;
 13→  const raycaster = new THREE.Raycaster();
 14→  const clock = new THREE.Clock();
 15→
 16→  const camera = new THREE.PerspectiveCamera(42, 1, 10, 100000);
 17→  const renderer = new THREE.WebGLRenderer({
 18→    antialias: true,
 19→    alpha: true,
 20→    powerPreference: 'high-performance',
 21→  });
 22→  renderer.outputColorSpace = THREE.SRGBColorSpace;
 23→  renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 2));
 24→  renderer.setSize(container.clientWidth || 1, container.clientHeight || 1, false);
 25→  renderer.domElement.style.width = '100%';
 26→  renderer.domElement.style.height = '100%';
 27→  renderer.domElement.style.display = 'block';
 28→  container.appendChild(renderer.domElement);
 29→
 30→  const inspectNavigation = createInspectNavigation({
 31→    camera,
 32→    domElement: renderer.domElement,
 33→  });
 34→
 35→  scene.add(new THREE.AmbientLight(0xffffff, 0.72));
 36→  scene.add(new THREE.HemisphereLight(0xdde7f4, 0xe6ded0, 0.7));
 37→  const keyLight = new THREE.DirectionalLight(0xffffff, 1.05);
 38→  keyLight.position.set(3500, 5000, 2000);
 39→  scene.add(keyLight);
 40→
 41→  let animationFrame = 0;
 42→  let worldRoot = null;
 43→  let gridHelper = null;
 44→  let currentBounds = null;
 45→  let pickHandler = null;
 46→  let pickContext = { activeFloorId: null };
 47→  let pointerDown = null;
 48→  let navigationMode = 'inspect';
 49→  let walkUiHandler = null;
 50→  let walkExitHandler = null;
 51→  let inspectState = null;
 52→  let activeFloorContext = {
 53→    floorId: null,
 54→    spawn: null,
 55→  };
 56→  const walkPoseByFloorId = new Map();
 57→  const walkNavigation = createWalkNavigation({
 58→    camera,
 59→    domElement: renderer.domElement,
 60→    onStateChange: () => {
 61→      emitWalkUiState();
 62→    },
 63→    onExitRequested: () => {
 64→      setNavigationMode('inspect');
 65→      walkExitHandler?.();
 66→    },
 67→  });
 68→
 69→  const emitWalkUiState = () => {
 70→    walkUiHandler?.({
 71→      navigationMode,
 72→      isLocked: navigationMode === 'walk' && walkNavigation.isLocked(),
 73→      canLock: navigationMode === 'walk',
 74→    });
 75→  };
 76→
 77→  const saveCurrentWalkPose = () => {
 78→    if (!activeFloorContext.floorId) return;
 79→    walkPoseByFloorId.set(activeFloorContext.floorId, walkNavigation.capturePose());
 80→  };
 81→
 82→  const restoreWalkPose = ({ forceSpawn = false } = {}) => {
 83→    if (!activeFloorContext.floorId) return;
 84→
 85→    const rememberedPose = !forceSpawn
 86→      ? walkPoseByFloorId.get(activeFloorContext.floorId)
 87→      : null;
 88→
 89→    if (rememberedPose) {
 90→      walkNavigation.restorePose(rememberedPose);
 91→      return;
 92→    }
 93→
 94→    const spawn = activeFloorContext.spawn;
 95→    if (!spawn?.position || !spawn.lookAt) return;
 96→
 97→    walkNavigation.restorePose({
 98→      position: [spawn.position.x, spawn.position.y, spawn.position.z],
 99→      lookAt: [spawn.lookAt.x, spawn.lookAt.y, spawn.lookAt.z],
100→    });
101→  };
102→
103→  const setNavigationMode = (nextMode = 'inspect') => {
104→    const resolvedMode = nextMode === 'walk' ? 'walk' : 'inspect';
105→    if (navigationMode === resolvedMode) {
106→      emitWalkUiState();
107→      return;
108→    }
109→
110→    if (navigationMode === 'inspect') {
111→      inspectState = inspectNavigation.captureState();
112→    }
113→
114→    if (navigationMode === 'walk') {
115→      saveCurrentWalkPose();
116→    }
117→
118→    navigationMode = resolvedMode;
119→    inspectNavigation.setEnabled(navigationMode === 'inspect');
120→    walkNavigation.setEnabled(navigationMode === 'walk');
121→
122→    if (navigationMode === 'inspect') {
123→      if (!inspectNavigation.restoreState(inspectState)) {
124→        inspectNavigation.resetView();
125→      }
126→    } else {
127→      restoreWalkPose();
128→    }
129→
130→    emitWalkUiState();
131→  };
132→
133→  const renderFrame = () => {
134→    const deltaSeconds = Math.min(clock.getDelta(), 0.1);
135→    if (navigationMode === 'inspect') {
136→      inspectNavigation.update(deltaSeconds);
137→    } else {
138→      walkNavigation.update(deltaSeconds);
139→    }
140→    renderer.render(scene, camera);
141→    animationFrame = window.requestAnimationFrame(renderFrame);
142→  };
143→
144→  const resize = () => {
145→    const width = container.clientWidth || 1;
146→    const height = container.clientHeight || 1;
147→    camera.aspect = width / height;
148→    camera.updateProjectionMatrix();
149→    renderer.setSize(width, height, false);
150→  };
151→
152→  const resolvePickTarget = (object) => {
153→    let current = object;
154→    while (current) {
155→      if (current.userData?.previewTarget) {
156→        return current.userData.previewTarget;
157→      }
158→      current = current.parent;
159→    }
160→    return null;
161→  };
162→
163→  const pickObjectAt = (clientX, clientY) => {
164→    if (navigationMode !== 'inspect') return;
165→    if (!worldRoot || !pickHandler) return;
166→
167→    const rect = renderer.domElement.getBoundingClientRect();
168→    if (!rect.width || !rect.height) return;
169→
170→    const pointer = new THREE.Vector2(
171→      ((clientX - rect.left) / rect.width) * 2 - 1,
172→      -(((clientY - rect.top) / rect.height) * 2 - 1)
173→    );
174→
175→    raycaster.setFromCamera(pointer, camera);
176→    const hits = raycaster.intersectObject(worldRoot, true);
177→    const seenTargets = new Set();
178→    const targets = [];
179→
180→    for (const hit of hits) {
181→      const target = resolvePickTarget(hit.object);
182→      if (!target) continue;
183→
184→      const key = `${target.floorId || ''}:${target.kind}:${target.sourceId}`;
185→      if (seenTargets.has(key)) continue;
186→      seenTargets.add(key);
187→      targets.push(target);
188→    }
189→
190→    if (!targets.length) {
191→      pickHandler(null);
192→      return;
193→    }
194→
195→    const preferredTarget = pickContext.activeFloorId
196→      ? targets.find((target) => target.floorId === pickContext.activeFloorId) || null
197→      : null;
198→
199→    pickHandler(preferredTarget || targets[0]);
200→  };
201→
202→  const handlePointerDown = (event) => {
203→    if (navigationMode !== 'inspect') {
204→      pointerDown = null;
205→      return;
206→    }
207→
208→    if (event.button !== 0) {
209→      pointerDown = null;
210→      return;
211→    }
212→
213→    pointerDown = {
214→      x: event.clientX,
215→      y: event.clientY,
216→    };
217→  };
218→
219→  const handlePointerCancel = () => {
220→    pointerDown = null;
221→  };
222→
223→  const handlePointerUp = (event) => {
224→    if (navigationMode !== 'inspect') {
225→      pointerDown = null;
226→      return;
227→    }
228→
229→    if (event.button !== 0 || !pointerDown) {
230→      pointerDown = null;
231→      return;
232→    }
233→
234→    const dx = event.clientX - pointerDown.x;
235→    const dy = event.clientY - pointerDown.y;
236→    pointerDown = null;
237→
238→    if (Math.hypot(dx, dy) > CLICK_DISTANCE_THRESHOLD) {
239→      return;
240→    }
241→
242→    pickObjectAt(event.clientX, event.clientY);
243→  };
244→
245→  renderer.domElement.addEventListener('pointerdown', handlePointerDown);
246→  renderer.domElement.addEventListener('pointerup', handlePointerUp);
247→  renderer.domElement.addEventListener('pointercancel', handlePointerCancel);
248→  renderer.domElement.addEventListener('pointerleave', handlePointerCancel);
249→
250→  animationFrame = window.requestAnimationFrame(renderFrame);
251→
252→  return {
253→    setWorld(nextRoot, bounds, groundLevel = 0) {
254→      const hadWorld = !!worldRoot;
255→      if (worldRoot) {
256→        scene.remove(worldRoot);
257→        disposeScene(worldRoot, { disposeMaterials: true });
258→      }
259→
260→      if (gridHelper) {
261→        scene.remove(gridHelper);
262→        gridHelper.geometry?.dispose?.();
263→        gridHelper.material?.dispose?.();
264→      }
265→
266→      worldRoot = nextRoot;
267→      currentBounds = descriptorBoundsToWorldBox(bounds);
268→      inspectNavigation.setBounds(currentBounds);
269→      gridHelper = createGrid(bounds, groundLevel);
270→      scene.add(gridHelper);
271→      scene.add(worldRoot);
272→      if (!hadWorld && navigationMode === 'inspect') {
273→        inspectNavigation.resetView();
274→      }
275→    },
276→    resetView() {
277→      if (navigationMode === 'walk') {
278→        if (activeFloorContext.floorId) {
279→          walkPoseByFloorId.delete(activeFloorContext.floorId);
280→        }
281→        restoreWalkPose({ forceSpawn: true });
282→        return;
283→      }
284→      inspectNavigation.resetView();
285→    },
286→    fit() {
287→      inspectNavigation.resetView();
288→    },
289→    setProjectionPreset(presetName) {
290→      inspectNavigation.setProjectionPreset(presetName);
291→    },
292→    setPickHandler(handler) {
293→      pickHandler = typeof handler === 'function' ? handler : null;
294→    },
295→    setPickContext(nextContext = {}) {
296→      pickContext = {
297→        ...pickContext,
298→        ...nextContext,
299→      };
300→    },
301→    setNavigationMode,
302→    setActiveFloorContext(nextContext = {}) {
303→      const previousFloorId = activeFloorContext.floorId;
304→      const nextFloorId = nextContext.floorId ?? activeFloorContext.floorId;
305→      const floorChanged = previousFloorId !== nextFloorId;
306→
307→      if (navigationMode === 'walk' && floorChanged && previousFloorId) {
308→        saveCurrentWalkPose();
309→      }
310→
311→      activeFloorContext = {
312→        ...activeFloorContext,
313→        ...nextContext,
314→      };
315→
316→      if (navigationMode === 'walk' && (floorChanged || !walkNavigation.isLocked())) {
317→        restoreWalkPose();
318→      }
319→    },
320→    setWalkUiHandler(handler) {
321→      walkUiHandler = typeof handler === 'function' ? handler : null;
322→      emitWalkUiState();
323→    },
324→    setWalkExitHandler(handler) {
325→      walkExitHandler = typeof handler === 'function' ? handler : null;
326→    },
327→    resize,
328→    dispose() {
329→      window.cancelAnimationFrame(animationFrame);
330→      inspectNavigation.dispose();
331→      walkNavigation.dispose();
332→      renderer.domElement.removeEventListener('pointerdown', handlePointerDown);
333→      renderer.domElement.removeEventListener('pointerup', handlePointerUp);
334→      renderer.domElement.removeEventListener('pointercancel', handlePointerCancel);
335→      renderer.domElement.removeEventListener('pointerleave', handlePointerCancel);
336→
337→      if (worldRoot) {
338→        scene.remove(worldRoot);
339→        disposeScene(worldRoot, { disposeMaterials: true });
340→      }
341→
342→      if (gridHelper) {
343→        scene.remove(gridHelper);
344→        gridHelper.geometry?.dispose?.();
345→        gridHelper.material?.dispose?.();
346→      }
347→
348→      disposeMaterialPalette(materialPalette);
349→      renderer.dispose();
350→      renderer.domElement.remove();
351→    },
352→    materialPalette,
353→  };
354→}
