  1→import { formatMeasurement } from '@/annotations/format';
  2→import { getBeamDisplayLabel } from '@/domain/beamLabels';
  3→import { getColumnListLabel } from '@/domain/columnLabels';
  4→import { getLandingDisplayLabel } from '@/domain/landingLabels';
  5→import { getSlabDisplayLabel } from '@/domain/slabLabels';
  6→import { getStairDisplayLabel } from '@/domain/stairLabels';
  7→import { beamLength } from '@/geometry/beamGeometry';
  8→import { slabArea } from '@/geometry/slabGeometry';
  9→import { stairRun, stairTotalRise } from '@/geometry/stairGeometry';
 10→import { wallLength } from '@/geometry/wallGeometry';
 11→
 12→const INSPECTABLE_TYPES = new Set([
 13→  'wall',
 14→  'beam',
 15→  'column',
 16→  'slab',
 17→  'stair',
 18→  'landing',
 19→  'door',
 20→  'window',
 21→]);
 22→
 23→const TYPE_LABELS = {
 24→  wall: 'Wall',
 25→  beam: 'Beam',
 26→  column: 'Column',
 27→  slab: 'Slab',
 28→  stair: 'Stair',
 29→  landing: 'Landing',
 30→  door: 'Door',
 31→  window: 'Window',
 32→};
 33→
 34→function mmRow(label, value) {
 35→  return { label, value: formatMeasurement(value || 0) };
 36→}
 37→
 38→function areaRow(label, value) {
 39→  return { label, value: `${(Math.abs(value || 0) / 1_000_000).toFixed(2)} m²` };
 40→}
 41→
 42→function findObjectInFloor(floor, selectedType, selectedId) {
 43→  switch (selectedType) {
 44→    case 'wall':
 45→      return floor.walls?.find((wall) => wall.id === selectedId) || null;
 46→    case 'beam':
 47→      return (floor.beams || []).find((beam) => beam.id === selectedId) || null;
 48→    case 'column':
 49→      return (floor.columns || []).find((column) => column.id === selectedId) || null;
 50→    case 'slab':
 51→      return (floor.slabs || []).find((slab) => slab.id === selectedId) || null;
 52→    case 'stair':
 53→      return (floor.stairs || []).find((stair) => stair.id === selectedId) || null;
 54→    case 'landing':
 55→      return (floor.landings || []).find((landing) => landing.id === selectedId) || null;
 56→    case 'door':
 57→      return floor.doors?.find((door) => door.id === selectedId) || null;
 58→    case 'window':
 59→      return floor.windows?.find((windowItem) => windowItem.id === selectedId) || null;
 60→    default:
 61→      return null;
 62→  }
 63→}
 64→
 65→function titleForObject(selectedType, object, floor) {
 66→  switch (selectedType) {
 67→    case 'beam':
 68→      return getBeamDisplayLabel(object, floor.columns || []);
 69→    case 'column':
 70→      return getColumnListLabel(object, floor.columns || []);
 71→    case 'slab':
 72→      return getSlabDisplayLabel(object);
 73→    case 'stair':
 74→      return getStairDisplayLabel(object);
 75→    case 'landing':
 76→      return getLandingDisplayLabel(object);
 77→    case 'wall':
 78→    case 'door':
 79→    case 'window':
 80→      return `${TYPE_LABELS[selectedType]} ${object.id.split('_').pop()}`;
 81→    default:
 82→      return object?.id || TYPE_LABELS[selectedType] || 'Object';
 83→  }
 84→}
 85→
 86→function rowsForObject(selectedType, object, floor) {
 87→  switch (selectedType) {
 88→    case 'wall':
 89→      return [
 90→        mmRow('Length', wallLength(object)),
 91→        mmRow('Thickness', object.thickness),
 92→        mmRow('Height', object.height),
 93→      ];
 94→    case 'beam':
 95→      return [
 96→        mmRow('Span', beamLength(object, floor.columns || [])),
 97→        mmRow('Width', object.width),
 98→        mmRow('Depth', object.depth),
 99→      ];
100→    case 'column':
101→      return [
102→        mmRow('Width', object.width),
103→        mmRow('Depth', object.depth),
104→        mmRow('Height', object.height),
105→      ];
106→    case 'slab':
107→      return [
108→        mmRow('Thickness', object.thickness),
109→        mmRow('Elevation', object.elevation),
110→        areaRow('Area', slabArea(object)),
111→      ];
112→    case 'stair':
113→      return [
114→        mmRow('Width', object.width),
115→        mmRow('Run', stairRun(object)),
116→        mmRow('Total Rise', stairTotalRise(object)),
117→      ];
118→    case 'landing':
119→      return [
120→        mmRow('Width', object.width),
121→        mmRow('Depth', object.depth),
122→        mmRow('Thickness', object.thickness),
123→      ];
124→    case 'door':
125→      return [
126→        mmRow('Width', object.width),
127→        mmRow('Height', object.height),
128→        mmRow('Sill', object.sillHeight),
129→      ];
130→    case 'window':
131→      return [
132→        mmRow('Width', object.width),
133→        mmRow('Height', object.height),
134→        mmRow('Sill', object.sillHeight),
135→      ];
136→    default:
137→      return [];
138→  }
139→}
140→
141→export function isPreviewInspectableType(selectedType) {
142→  return INSPECTABLE_TYPES.has(selectedType);
143→}
144→
145→export function getPreviewInspection(project, selectedType, selectedId) {
146→  if (!selectedId || !isPreviewInspectableType(selectedType)) return null;
147→
148→  for (const floor of project?.floors || []) {
149→    const object = findObjectInFloor(floor, selectedType, selectedId);
150→    if (!object) continue;
151→
152→    return {
153→      id: selectedId,
154→      type: selectedType,
155→      floorId: floor.id,
156→      floorName: floor.name,
157→      title: titleForObject(selectedType, object, floor),
158→      subtitle: `${floor.name} · ${TYPE_LABELS[selectedType]}`,
159→      rows: rowsForObject(selectedType, object, floor),
160→    };
161→  }
162→
163→  return null;
164→}
